37	EnterAutomaticScopeGuard::EnterAutomaticScopeGuard(EvalContext &context, const ast::Scope *scope)
38		: context(context), scope(scope)
39	{
40		if (scope) {
41			++context.scope_nest_level[scope];
42		}
43	}
44	
45	EnterAutomaticScopeGuard::~EnterAutomaticScopeGuard()
46	{
47		if (scope) {
48			auto new_nest_level = --context.scope_nest_level.at(scope);
49			log_assert(new_nest_level >= 0);
50			if (new_nest_level == 0)
51				context.scope_nest_level.erase(scope);
52		}
53	}
