55	RegisterEscapeConstructGuard::RegisterEscapeConstructGuard(ProceduralContext &context,
56			EscapeConstructKind kind, const ast::SubroutineSymbol *subroutine)
57		: flag(Variable::escape_flag(context.flag_counter++)), context(context)
58	{
59		assert(kind == EscapeConstructKind::FunctionBody);
60		context.escape_stack.emplace_back();
61		auto &construct = context.escape_stack.back();
62		construct.kind = kind;
63		construct.subroutine = subroutine;
64		construct.flag = flag;
65		context.do_simple_assign(subroutine->location, flag, RTLIL::S0, true);
66	}
