68	RegisterEscapeConstructGuard::RegisterEscapeConstructGuard(
69			ProceduralContext &context, EscapeConstructKind kind, const ast::Statement *statement)
70		: flag(Variable::escape_flag(context.flag_counter++)), context(context)
71	{
72		log_assert(kind == EscapeConstructKind::Loop || kind == EscapeConstructKind::LoopBody);
73		context.escape_stack.emplace_back();
74		auto &construct = context.escape_stack.back();
75		construct.kind = kind;
76		construct.flag = flag;
77		context.do_simple_assign(statement->sourceRange.start(), flag, RTLIL::S0, true);
78	}
