86	void ProceduralContext::signal_escape(slang::SourceLocation loc, EscapeConstructKind kind)
87	{
88		auto it = escape_stack.rbegin();
89		while (it != escape_stack.rend()) {
90			do_simple_assign(loc, it->flag, RTLIL::S1, true);
91			if (it->kind == kind)
92				break;
93			it++;
94		}
95		log_assert(it != escape_stack.rend());
96	}
97	
98	const ast::SubroutineSymbol *ProceduralContext::get_current_subroutine()
99	{
100		for (auto it = escape_stack.rbegin(); it != escape_stack.rend(); it++) {
101			if (it->kind == EscapeConstructKind::FunctionBody)
102				return it->subroutine;
103		}
104		log_abort();
105	}
