123	void ProceduralContext::inherit_state(ProceduralContext &other)
124	{
125		assert(&netlist == &other.netlist);
126		assert(eval.scope_nest_level == other.eval.scope_nest_level);
127		assert(seen_blocking_assignment.empty());
128		assert(seen_nonblocking_assignment.empty());
129		seen_blocking_assignment = other.seen_blocking_assignment;
130		seen_nonblocking_assignment = other.seen_nonblocking_assignment;
131		preceding_memwr = other.preceding_memwr;
132		vstate = other.vstate;
133		flag_counter = other.flag_counter;
134	}
