141	VariableBits ProceduralContext::all_driven()
142	{
143		VariableBits all_driven;
144		for (auto pair : vstate.visible_assignments) {
145			all_driven.append(pair.first);
146		}
147	
148		all_driven.sort_and_unify();
149	
150		VariableBits all_driven_filtered;
151		for (auto chunk : all_driven.chunks())
152			if (chunk.variable.kind == Variable::Static)
153				all_driven_filtered.append(VariableBits(chunk));
154	
155		return all_driven_filtered;
156	}
