158	RTLIL::SigBit ProceduralContext::case_enable()
159	{
160		if (timing.kind == ProcessTiming::Initial) {
161			return RTLIL::S1;
162		} else {
163			RTLIL::SigBit ret = netlist.add_placeholder_signal(1);
164			root_case->aux_actions.emplace_back(ret, RTLIL::State::S0);
165			current_case->aux_actions.emplace_back(ret, RTLIL::State::S1);
166			return ret;
167		}
168	}
