170	void crop_zero_mask(const RTLIL::SigSpec &mask, RTLIL::SigSpec &target)
171	{
172		for (int i = mask.size() - 1; i >= 0; i--) {
173			if (mask[i] == RTLIL::S0)
174				target.remove(i, 1);
175		}
176	}
177	
178	void crop_zero_mask(const RTLIL::SigSpec &mask, VariableBits &target)
179	{
180		for (int i = mask.size() - 1; i >= 0; i--) {
181			if (mask[i] == RTLIL::S0)
182				target.remove(i);
183		}
184	}
