313	RTLIL::SigSpec ProceduralContext::substitute_rvalue(VariableBits bits)
314	{
315		RTLIL::SigSpec subed;
316	
317		if (timing.kind == ProcessTiming::Initial) {
318			// No non-blocking assignments allowed in initial procedures.
319			for (auto [base, size, chunk] : bits.chunk_spans()) {
320				switch (chunk.variable.kind) {
321				case Variable::Dummy:
322				case Variable::Invalid: log_abort();
323	
324				case Variable::Local:
325				case Variable::EscapeFlag:
326					for (uint64_t i = 0; i < size; i++) {
327						subed.append(initial_locals_state.at(chunk[i], RTLIL::Sx));
328					}
329					break;
330				case Variable::Static:
331					for (uint64_t i = 0; i < size; i++) {
332						subed.append(netlist.initial_state.at(chunk[i], RTLIL::Sx));
333					}
334					break;
335				default: log_abort();
336				}
337			}
338		} else {
339			for (auto chunk : bits.chunks()) {
340				// We disallow mixing of blocking and non-blocking assignments to the
341				// same variable from the same process. That simplifies the handling
342				// here.
343				if (chunk.variable.kind != Variable::Static ||
344						seen_blocking_assignment.count(chunk.variable))
345					subed.append(vstate.evaluate(netlist, chunk));
346				else
347					subed.append(netlist.convert_static(chunk));
348			}
349		}
350	
351		return subed;
352	}
