439	void ProceduralContext::assign_rvalue(
440			const ast::AssignmentExpression &assign, RTLIL::SigSpec rvalue)
441	{
442		if (assign.timingControl && !netlist.settings.ignore_timing.value_or(false))
443			netlist.add_diag(diag::GenericTimingUnsyn, assign.timingControl->sourceRange);
444	
445		bool blocking = !assign.isNonBlocking();
446		const ast::Expression *raw_lexpr = &assign.left();
447	
448		if (raw_lexpr->kind == ast::ExpressionKind::Streaming) {
449			auto &stream_lexpr = raw_lexpr->as<ast::StreamingConcatenationExpression>();
450			VariableBits lvalue = eval.streaming_lhs(stream_lexpr);
451			ast_invariant(assign, (uint64_t)rvalue.size() >= lvalue.bitwidth());
452			do_simple_assign(assign.sourceRange.start(), lvalue,
453					rvalue.extract_end(rvalue.size() - lvalue.bitwidth()), blocking);
454			return;
455		} else if (raw_lexpr->kind == ast::ExpressionKind::SimpleAssignmentPattern) {
456			// break down into individual assignments
457			auto &pattern_lexpr = raw_lexpr->as<ast::SimpleAssignmentPatternExpression>();
458	
459			int nbits_remaining = rvalue.size();
460			for (auto el : pattern_lexpr.elements()) {
461				log_assert(el->kind == ast::ExpressionKind::Assignment);
462				auto &inner_assign = el->as<ast::AssignmentExpression>();
463	
464				const ast::Expression *rsymbol = &inner_assign.right();
465				while (rsymbol->kind == ast::ExpressionKind::Conversion)
466					rsymbol = &rsymbol->as<ast::ConversionExpression>().operand();
467				log_assert(rsymbol->kind == ast::ExpressionKind::EmptyArgument);
468				log_assert(rsymbol->type->isBitstreamType());
469				int relem_width = rsymbol->type->getBitstreamWidth();
470	
471				log_assert(nbits_remaining >= relem_width);
472				RTLIL::SigSpec relem = rvalue.extract(nbits_remaining - relem_width, relem_width);
473				nbits_remaining -= relem_width;
474	
475				assign_rvalue(inner_assign, eval.apply_nested_conversion(inner_assign.right(), relem));
476			}
477	
478			log_assert(nbits_remaining == 0);
479			return;
480		}
481		auto analyzed_lvalue = LValue::analyze(this->eval, *raw_lexpr, false);
482		if (analyzed_lvalue) {
483			assign_to_lvalue_with_masking(assign, *this, *analyzed_lvalue, rvalue,
484					RTLIL::SigSpec(RTLIL::S1, rvalue.size()), blocking);
485		}
486	}
