496	UnrollLimitTracking::UnrollLimitTracking(NetlistContext &netlist, int limit)
497		: netlist(netlist), limit(limit)
498	{}
499	
500	UnrollLimitTracking::~UnrollLimitTracking()
501	{
502		log_assert(!unrolling);
503	}
504	
505	void UnrollLimitTracking::enter_unrolling()
506	{
507		if (!unrolling++) {
508			unroll_counter = 0;
509			error_issued = false;
510			loops.clear();
511		}
512	}
513	
514	void UnrollLimitTracking::exit_unrolling()
515	{
516		unrolling--;
517		log_assert(unrolling >= 0);
518	}
519	
520	bool UnrollLimitTracking::unroll_tick(const ast::Statement *symbol)
521	{
522		if (error_issued)
523			return false;
524	
525		loops.insert(symbol);
526	
527		if (++unroll_counter > limit) {
528			auto &diag = netlist.add_diag(diag::UnrollLimitExhausted, symbol->sourceRange);
529			diag << limit;
530			for (auto other_loop : loops) {
531				if (other_loop == symbol)
532					continue;
533				diag.addNote(diag::NoteLoopContributes, other_loop->sourceRange);
534			}
535			error_issued = true;
536			return false;
537		}
538	
539		return true;
540	}
